import './App.css';
import './About.css';
import NavBar from './NavBar';
import Footer from './Footer';
import React, {useState, useEffect} from 'react';

import profilePic from './img/profilePic.jpg';
import { profile } from 'console';

function About() {


  return (
    <div>
      <NavBar></NavBar>

        <div id="" className="content-left content-margintop content-padding">

            <div className="splitGrid">
              <div className='splitDiv leftSplit'>
                <h1>Project Title</h1>
                <h2>This is a one sentence description of the project, catchy!</h2>
            </div>


              <div className='splitDiv rightSplit'>
                  <img src={profilePic} style={{"width":"100%","border-radius":"2%"}}/>
              </div>

            </div>

        </div>
        <Footer></Footer>
    </div>
  );
}

export default About;
